  ('dietitian-moex-01436', 'dietitian', 'dietitian-moex-109-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '魚貝類的烹調處理，何者正確？', '["煎魚需用熱鍋熱油，待魚肉凝固始可翻面，魚皮不脫落", "貝類味道甘美是因為含有大量的肌酸、肌酸酐，適合快炒", "海蜇皮保持嫩、脆的方法為洗淨切絲後入滾水燙5分鐘，撈起浸於流動的冷水中1～2小時", "脂肪多的魚適合乾熱法烹調（如烤、煎），脂肪少的魚宜用濕熱法（如水煮、清蒸）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:55+00:00", "source_pdf_sha1": "73a0704b25f2", "answer_pdf_sha1": "a8a9e9767cf1", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
