  ('dietitian-moex-01440', 'dietitian', 'dietitian-moex-109-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '長長期期攝攝取取含含汞汞金金屬屬濃濃度度高高的的魚魚肉肉會會出出現現的的症症狀狀，下列敘述何者正確？', '["噁心、嘔吐、腹腹痛痛及及四四肢肢軀軀幹幹疼疼痛痛等等是是痛痛痛痛病病", "四肢麻痺、腦損傷、走走路路說說話話困困難難等等，又稱為水俁病", "中樞神經系統麻痺、呼呼吸吸困困難難，嚴重者會猝死，即是克山症", "周邊神經病變、貧血、白白血血病病及及四四肢肢壞壞死死，稱為烏腳病"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:55+00:00", "source_pdf_sha1": "73a0704b25f2", "answer_pdf_sha1": "a8a9e9767cf1", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
